import Q from "../../../../../../../../../../../subject_repositories/q/q.js";

describe("Q isInternalFrame fileName check", () => {
  it("only filters frames from q.js, not from other files at same line numbers", async () => {
    Q.longStackSupport = true;

    try {
      const probe = Q.defer();
      const realStack: string = (probe.promise as any).stack || "";
      probe.resolve(null);

      if (!realStack) return;

      let lineInRange: number | null = null;
      for (const line of realStack.split("\n")) {
        const m = line.match(/:(\d+):\d+\)/) || line.match(/:(\d+):\d+$/);
        if (m) {
          lineInRange = parseInt(m[1]);
          break;
        }
      }

      if (!lineInRange) return;

      const deferred = Q.defer();
      deferred.promise.stack = `    at fn (/different/file.js:${lineInRange}:1)`;
      deferred.promise.stackCounter = 1;

      const err = new Error("test");
      deferred.reject(err);
      const caught = await deferred.promise.then(null, (e: Error) => e);

      expect(caught.stack).toContain("different/file.js");
    } finally {
      Q.longStackSupport = false;
    }
  });
});
